using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchive now always sets the UTF-8 EFS
        // flag, so legacy consumers ignore the raw bytes and decode as UTF-8.
        // Explicitly pass Shift-JIS so the entry names are encoded in Shift-JIS
        // *without* the EFS flag, which the legacy Java reader expects.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("Shift_JIS");
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

// .NET 9 breaking change: keyed and non-keyed DI registrations are
// now strictly separated. A [FromKeyedServices("cache")] parameter
// requires a keyed registration; a non-keyed AddSingleton no longer
// satisfies it.
services.AddKeyedSingleton<ICache, RedisCache>("cache");

